"""
Imágenes embebidas en Base64 para la generación de certificados catastrales.
Esto garantiza que las imágenes siempre estén disponibles sin depender de archivos externos.
"""
import base64
import io
from pathlib import Path

# Encabezado del certificado (logo institucional)
ENCABEZADO_BASE64 = """
"""

# Pie de página del certificado
PIE_PAGINA_BASE64 = """
"""

# Firma de Dalgie Esperanza Torrado Rizo
FIRMA_DALGIE_BASE64 = """
"""

def get_image_from_base64(base64_string: str) -> io.BytesIO:
    """Convierte una cadena base64 a un objeto BytesIO que puede ser usado por ReportLab."""
    image_data = base64.b64decode(base64_string.strip())
    return io.BytesIO(image_data)

def get_encabezado_image() -> io.BytesIO:
    """Retorna la imagen del encabezado como BytesIO."""
    return get_image_from_base64(ENCABEZADO_BASE64)

def get_pie_pagina_image() -> io.BytesIO:
    """Retorna la imagen del pie de página como BytesIO."""
    return get_image_from_base64(PIE_PAGINA_BASE64)

def get_firma_dalgie_image() -> io.BytesIO:
    """Retorna la imagen de la firma de Dalgie como BytesIO."""
    return get_image_from_base64(FIRMA_DALGIE_BASE64)
